from __future__ import annotations
from html import escape
from config.settings import REPORT_DIR
def render(run):
 findings=run["findings"];counts={k:sum(f["severity"]==k for f in findings) for k in ["critical","high","medium","low","info"]};rows="".join(f"<tr><td><span class='badge {escape(f['severity'])}'>{escape(f['severity'])}</span></td><td>{escape(f['scanner'])}</td><td>{escape(f['title'])}</td><td>{escape(f['evidence'])}</td><td>{escape(f['recommendation'])}</td></tr>" for f in findings) or "<tr><td colspan='5'>No findings.</td></tr>"
 return f"""<!doctype html><html><head><meta charset='utf-8'><title>Security Barbie report #{run['id']}</title><style>body{{font:16px system-ui;margin:3rem;background:#fff7fb;color:#25141d}}.card{{background:white;border:1px solid #f0cade;border-radius:14px;padding:1.2rem;margin:1rem 0}}table{{width:100%;border-collapse:collapse}}td,th{{padding:.65rem;border-bottom:1px solid #eee;text-align:left}}.badge{{padding:.2rem .5rem;border-radius:999px;font-size:.8rem}}.critical{{background:#5d1010;color:#fff}}.high{{background:#b83b22;color:#fff}}.medium{{background:#f3ce65}}.low{{background:#b9dbef}}.info{{background:#e8e8e8}}</style></head><body><h1>🛡️ Security Barbie</h1><div class='card'><b>Target:</b> {escape(run['target'])}<br><b>Run:</b> #{run['id']} · {escape(run['started_at'])}<br><b>Status:</b> {escape(run['status'])}</div><div class='card'><b>Critical</b> {counts['critical']} · <b>High</b> {counts['high']} · <b>Medium</b> {counts['medium']} · <b>Low</b> {counts['low']} · <b>Info</b> {counts['info']}</div><table><thead><tr><th>Severity</th><th>Check</th><th>Finding</th><th>Evidence</th><th>Recommended action</th></tr></thead><tbody>{rows}</tbody></table><p>Safe, authorized, unauthenticated assessment only.</p></body></html>"""
def write(run):
 path=REPORT_DIR/f"security-run-{run['id']}.html";path.write_text(render(run),encoding="utf-8");return str(path)
